            old(heap).is_heap(),
            old(heap).len < BinaryMaxHeap::max_capacity(),
            old(heap).storage.len() > old(heap).len, 
        ensures
            heap.is_heap(),
            heap.len == old(heap).len + 1,
            heap.view() =~= old(heap).view().insert(v),
    // </spec>
    // <code>
    {
        let old_len = heap.len;
        let ghost old_storage_view = heap.storage.view();
        let ghost old_heap_view = heap.view();

        // 1. Initial Step: Place the new element at the first available position
