        assert(seq_mid.to_multiset() =~= old_storage_view.take(old_len as int).to_multiset().insert(v));
        assert(heap.view() =~= old_heap_view.insert(v));

        let mut curr = old_len;

        // 2. Bubble-up (sift-up) process to restore the max-heap property
        while curr > 0
            invariant
                heap.len == old_len + 1,
                heap.len <= heap.storage.len(),
                heap.len <= BinaryMaxHeap::max_capacity(),
                0 <= curr < heap.len,
                heap.storage[curr as int] == v,
                heap.view() =~= old_heap_view.insert(v),
